import java.io.IOException;
import java.util.Scanner;

public class SecureCommandExecutionExample {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter a file name to list: ");
        String fileName = scanner.nextLine();

        try {
            // Use ProcessBuilder to safely execute the command
            Process process = new ProcessBuilder("ls", fileName).start();

            // Read and display the output of the command
            java.util.Scanner processScanner = new java.util.Scanner(process.getInputStream()).useDelimiter("\\A");
            String output = processScanner.hasNext() ? processScanner.next() : "";

            // Print the output of the command
            System.out.println("Listing files in " + fileName + ":");
            System.out.println(output);
        } catch (IOException e) {
            System.out.println("Error executing command: " + e.getMessage());
        }
    }
}

